func runBlockedHeartbeatLoop(t *testing.T, store *bead.Store, heartbeatInterval time.Duration) (func(), <-chan error) {
	t.Helper()

	started := make(chan struct{})
	release := make(chan struct{})
	done := make(chan error, 1)

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			select {
			case <-started:
			default:
				close(started)
			}
			<-release
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-heartbeat",
				ResultRev: "deadbeef",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{
		Assignee:          "worker",
		HeartbeatInterval: heartbeatInterval,
	}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	go func() {
		_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
		done <- err
	}()

	require.Eventually(t, func() bool {
		select {
		case <-started:
			return true
		default:
			return false
		}
	}, time.Second, 5*time.Millisecond, "worker never started")

	return func() {
		close(release)
	}, done
}

func TestWorkLoop_ClaimLivenessDoesNotMutateBeadsJSONL(t *testing.T) {
	store, _, _ := newExecuteLoopTestStore(t)

	release, done := runBlockedHeartbeatLoop(t, store, 5*time.Millisecond)

	before, err := os.ReadFile(store.File)
	require.NoError(t, err)

	time.Sleep(50 * time.Millisecond)

	after, err := os.ReadFile(store.File)
	require.NoError(t, err)

	require.Equal(t, before, after, "heartbeat refresh must not rewrite beads.jsonl")
	release()
	require.NoError(t, <-done)
}

func TestWorkLoop_LivenessRecordedOutsideTracker(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)

	release, done := runBlockedHeartbeatLoop(t, store, 5*time.Millisecond)

	trackerBefore, err := os.ReadFile(store.File)
	require.NoError(t, err)
	require.NoError(t, store.TouchClaimHeartbeat(first.ID))
	fresh, _, err := store.ClaimHeartbeatFresh(first.ID)
	require.NoError(t, err)
	require.True(t, fresh, "store must read the external claim lease as fresh")
	time.Sleep(50 * time.Millisecond)
	trackerAfter, err := os.ReadFile(store.File)
	require.NoError(t, err)
	require.Equal(t, trackerBefore, trackerAfter, "lease refresh must stay outside beads.jsonl")

	release()
	require.NoError(t, <-done)
}

package bead

import (
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const claimLivenessNamespace = "ddx-claim-heartbeats"

type claimLivenessRecord struct {
	BeadID    string    `json:"bead_id"`
	UpdatedAt time.Time `json:"updated_at"`
	PID       int       `json:"pid,omitempty"`
}

func claimLivenessPath(ddxDir, id string) string {
	root := canonicalClaimRoot(ddxDir)
	sum := sha1.Sum([]byte(root))
	return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
}

func canonicalClaimRoot(ddxDir string) string {
	root := filepath.Clean(filepath.Dir(ddxDir))
	if abs, err := filepath.Abs(root); err == nil {
		root = abs
	}
	if real, err := filepath.EvalSymlinks(root); err == nil {
		root = real
	}
	return filepath.Clean(root)
}

func writeAtomicClaimFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
	}
	tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
	if err != nil {
		return fmt.Errorf("bead: create claim liveness tmp: %w", err)
	}
	tmpName := tmp.Name()
	defer func() {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
	}()
	if _, err := tmp.Write(data); err != nil {
		return fmt.Errorf("bead: write claim liveness tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		return fmt.Errorf("bead: close claim liveness tmp: %w", err)
	}
	if err := os.Rename(tmpName, path); err != nil {
		return fmt.Errorf("bead: publish claim liveness: %w", err)
	}
	return nil
}

func (s *Store) TouchClaimHeartbeat(id string) error {
	rec := claimLivenessRecord{
		BeadID:    id,
		UpdatedAt: time.Now().UTC(),
		PID:       os.Getpid(),
	}
	data, err := json.Marshal(rec)
	if err != nil {
		return fmt.Errorf("bead: marshal claim liveness: %w", err)
	}
	data = append(data, '\n')
	return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
}

func (s *Store) RemoveClaimHeartbeat(id string) error {
	err := os.Remove(claimLivenessPath(s.Dir, id))
	if err == nil || os.IsNotExist(err) {
		return nil
	}
	return fmt.Errorf("bead: remove claim liveness: %w", err)
}

func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
	data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
	if os.IsNotExist(err) {
		return false, false, nil
	}
	if err != nil {
		return false, false, fmt.Errorf("bead: read claim liveness: %w", err)
	}
	var rec claimLivenessRecord
	if err := json.Unmarshal(data, &rec); err != nil {
		return false, true, fmt.Errorf("bead: parse claim liveness: %w", err)
	}
	if rec.UpdatedAt.IsZero() {
		return false, true, nil
	}
	return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
}

